mapper.select:
SELECT eb.id, eb.question_id, q.type AS question_type, q.difficulty, q.content AS question_content, q.options, q.answer, q.explanation, q.subject_id, s.name AS subject_name, eb.error_reason, eb.is_mastered, eb.review_count, eb.consecutive_correct, eb.review_interval_days, eb.next_review_at, eb.created_at, eb.updated_at FROM t_error_book eb INNER JOIN t_question q ON eb.question_id = q.id LEFT JOIN t_subject s ON q.subject_id = s.id WHERE eb.user_id = #{userId}
AND q.subject_id = #{subjectId}
AND eb.is_mastered = #{isMastered}
ORDER BY eb.updated_at DESC
